"use strict";const astUtils=require("./ast-utils");class FixTracker{constructor(e,t){this.fixer=e,this.sourceCode=t,this.retainedRange=null}retainRange(e){return this.retainedRange=e,this}retainEnclosingFunction(e){const t=astUtils.getUpperFunction(e);return this.retainRange(t?t.range:this.sourceCode.ast.range)}retainSurroundingTokens(e){const t=this.sourceCode.getTokenBefore(e)||e,r=this.sourceCode.getTokenAfter(e)||e;return this.retainRange([t.range[0],r.range[1]])}replaceTextRange(e,t){let r;return r=this.retainedRange?[Math.min(this.retainedRange[0],e[0]),Math.max(this.retainedRange[1],e[1])]:e,this.fixer.replaceTextRange(r,this.sourceCode.text.slice(r[0],e[0])+t+this.sourceCode.text.slice(e[1],r[1]))}remove(e){return this.replaceTextRange(e.range,"")}}module.exports=FixTracker;